"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[364],{247:e=>{e.exports=JSON.parse('{"functions":[{"name":"State","desc":"Creates a new reactive `State` object that can be bound to GUI updates. Call `Set` on\\nthe returned object to update the state and trigger UI updates.\\n\\n```lua\\nlocal coins: Flux.State<number> = Flux:State(0)\\ncontroller:Bind(coins, function(n: number) label.Text = tostring(n) end)\\ncoins:Set(42)\\n```","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"initialValue","desc":"An optional starting value","lua_type":"T?"}],"returns":[{"desc":"","lua_type":"State<T>"}],"function_type":"static","source":{"line":126,"path":"src/Flux/init.luau"}},{"name":"Computed","desc":"Creates a reactive derived state value. The callback runs immediately to seed the value,\\nthen re-runs whenever any dependency changes. The returned state is read-only from the\\ncaller perspective and is cleaned up automatically when its dependencies are destroyed.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"callback","desc":"A function that derives the computed value from current dependencies","lua_type":"() -> T"},{"name":"dependencies","desc":"Optional array of states to observe; if omitted, the callback is evaluated once","lua_type":"{State<any>}?"}],"returns":[{"desc":"","lua_type":"State<T>"}],"function_type":"static","source":{"line":139,"path":"src/Flux/init.luau"}},{"name":"Compose","desc":"Composes multiple components into one component. The returned component invokes each\\ncomponent in order using the same `instance`, `scope`, and `properties`.\\n\\n```lua\\nlocal FancyButton = Flux:Compose({\\n\\tHoverEffect,\\n\\tClickEffect,\\n\\tPulseEffect,\\n})\\ncontroller:Mount(FancyButton, button, {theme = themeState})\\n```","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"components","desc":"Components to run in sequence for the same instance and scope","lua_type":"{Component}"}],"returns":[{"desc":"","lua_type":"Component"}],"function_type":"static","source":{"line":234,"path":"src/Flux/init.luau"}},{"name":"Tween","desc":"Returns an `AnimatedState` that smoothly interpolates toward `source` whenever it changes,\\nusing `TweenInfo` for timing and easing. Supports `number` and any Roblox type with a `:Lerp`\\nmethod (UDim2, Vector2, Vector3, Color3, CFrame, UDim). Call `Destroy` when finished.\\n\\n```lua\\nlocal health = Flux:State(100)\\nlocal animHealth = Flux:Tween(health, TweenInfo.new(0.4, Enum.EasingStyle.Quad))\\nscope:BindProperty(animHealth, bar, \\"Size\\")\\nhealth:Set(50)\\n```","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"source","desc":"The reactive state to animate","lua_type":"State<T>"},{"name":"tweenInfo","desc":"Controls duration, easing style, and easing direction","lua_type":"TweenInfo"}],"returns":[{"desc":"","lua_type":"AnimatedState<T>"}],"function_type":"static","source":{"line":264,"path":"src/Flux/init.luau"}},{"name":"Spring","desc":"Returns an `AnimatedState` driven by spring physics that follows `source` whenever it changes.\\nSupports `number`, Vector2, Vector3, Color3, and UDim2. The Heartbeat connection is only active\\nwhile the spring is moving and disconnects automatically when settled. Call `Destroy` when finished.\\n\\n```lua\\nlocal open = Flux:State(UDim2.fromScale(0, 0))\\nlocal animOpen = Flux:Spring(open, 20, 1)\\nscope:BindProperty(animOpen, panel, \\"Size\\")\\nopen:Set(UDim2.fromScale(1, 1))\\n```","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"source","desc":"The reactive state to animate","lua_type":"State<T>"},{"name":"speed","desc":"Angular frequency \u2014 how quickly the spring responds (e.g. 15\u201325 for snappy UI)","lua_type":"number"},{"name":"damping","desc":"Damping ratio \u2014 1 is critically damped (no overshoot), < 1 is bouncy","lua_type":"number"}],"returns":[{"desc":"","lua_type":"AnimatedState<T>"}],"function_type":"static","source":{"line":288,"path":"src/Flux/init.luau"}},{"name":"MountScreenGui","desc":"Parents the given `ScreenGui` to the local player\'s `PlayerGui` and returns a `Controller`\\nthat owns its lifecycle. The caller is responsible for cloning templates before passing them in.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"gui","desc":"The GUI instance to mount","lua_type":"ScreenGui"}],"returns":[{"desc":"","lua_type":"Controller"}],"function_type":"static","source":{"line":303,"path":"src/Flux/init.luau"}},{"name":"MountSurfaceGui","desc":"Sets the `Adornee` (and optionally `Face`) on the given `SurfaceGui`, parents it to the local\\nplayer\'s `PlayerGui`, and returns a `Controller` that owns its lifecycle. The caller is\\nresponsible for cloning templates before passing them in.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"gui","desc":"The GUI instance to mount","lua_type":"SurfaceGui"},{"name":"adornee","desc":"The part the SurfaceGui will be attached to","lua_type":"BasePart"},{"name":"face","desc":"The face of the part the SurfaceGui will be attached to (optional)","lua_type":"Enum.NormalId?"}],"returns":[{"desc":"","lua_type":"Controller"}],"function_type":"static","source":{"line":324,"path":"src/Flux/init.luau"}},{"name":"MountBillboardGui","desc":"Sets the `Adornee` on the given `BillboardGui`, parents it to the local player\'s `PlayerGui`,\\nand returns a `Controller` that owns its lifecycle. The caller is responsible for cloning\\ntemplates before passing them in.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"gui","desc":"The GUI instance to mount","lua_type":"BillboardGui"},{"name":"adornee","desc":"The part the BillboardGui will be attached to","lua_type":"BasePart"}],"returns":[{"desc":"","lua_type":"Controller"}],"function_type":"static","source":{"line":352,"path":"src/Flux/init.luau"}}],"properties":[],"types":[{"name":"Scope","desc":"A minimal lifecycle scope passed to each component function. Use `Bind` to subscribe to reactive state,\\n`BindProperty` to drive a named instance property directly from state, `OnEvent` to connect instance\\nevents, `Mount` to compose child components, and `MountWhen` for conditional rendering.\\nAll bindings, event connections, and child mounts made through this scope are automatically\\ncleaned up when the parent GUI is unmounted.","fields":[{"name":"Bind","lua_type":"(self, state: State<T>, callback: (newValue: T?) -> ()) -> ()","desc":"Binds to a `State` scoped to this component\'s lifecycle"},{"name":"BindProperty","lua_type":"(self, state: State<T>, instance: Instance, property: string) -> ()","desc":"Binds a `State` directly to a named property on an instance"},{"name":"OnEvent","lua_type":"(self, instance: Instance, eventName: string, callback: (...any) -> ()) -> ()","desc":"Connects an instance event scoped to this component\'s lifecycle"},{"name":"Mount","lua_type":"(self, component: Component, instance: Instance, properties: {[string]: any}?) -> ()","desc":"Mounts a child component scoped to this component\'s lifecycle"},{"name":"MountWhen","lua_type":"(self, condition: State<boolean>, component: Component, instance: Instance, properties: {[string]: any}?) -> ()","desc":"Conditionally mounts a child component based on state"}],"source":{"line":23,"path":"src/Flux/init.luau"}},{"name":"Component","desc":"A reusable function that applies behavior to a GUI child `Instance`. Components are mounted to a specific\\n`Instance` in the GUI hierarchy and can bind to reactive state using the provided `Scope`. Components\\nshould be used for reusable pieces of UI behavior. For example, you might have a \\"HealthBar\\" component that\\nyou mount to any Frame to turn it into a health bar, or a \\"Draggable\\" component that makes any GUI element\\ndraggable. Components should not manage the lifecycle of their own `Instance` (i.e. by destroying it or\\nreparenting it), they should only be responsible for updating the instance\'s properties in response to state changes,\\npassed down through `properties` or observed via `Bind`. Let the parent `Controller` manage the lifecycle of all instances.","lua_type":"(instance: Instance, scope: Scope, properties: {[string]: any}?) -> ()","source":{"line":37,"path":"src/Flux/init.luau"}},{"name":"State","desc":"A reactive state object. Create these using `Flux:State` and pass them to\\n`Controller:Bind` or `Scope:Bind` inside components to reactively drive UI updates.","source":{"line":46,"path":"src/Flux/init.luau"}},{"name":"AnimatedState","desc":"A read-only animated state returned by `Flux:Tween` and `Flux:Spring`. Supports `Get`, `Observe`,\\nand `Destroy` \u2014 compatible with `Bind` and `BindProperty`. Call `Destroy` when you are finished\\nwith it to stop the animation and free resources.","source":{"line":56,"path":"src/Flux/init.luau"}},{"name":"Self","desc":"","lua_type":"Flux","source":{"line":77,"path":"src/Flux/init.luau"}}],"name":"Flux","desc":"Client module for mounting and managing GUI instances. Each mount parents the GUI to\\n`PlayerGui` and returns a `Controller` that owns the instance\'s lifecycle.\\nThe caller is responsible for cloning templates before passing them in.\\n\\n```lua\\nlocal Flux = require(ReplicatedStorage.Flux)\\n\\n-- Create reactive state\\nlocal coins: Flux.State<number> = Flux:State(0)\\n\\n-- Clone and mount the GUI\\nlocal gui = ReplicatedStorage.Assets.Gui.CoinScreenGui:Clone()\\nlocal controller = Flux:MountScreenGui(gui)\\n\\n-- Bind state to UI\\ncontroller:Bind(coins, function(count: number)\\n\\tlocal frame = controller:GetInstance():FindFirstChild(\\"Frame\\")\\n\\tif frame then\\n\\t\\tlocal coinsLabel = frame:FindFirstChild(\\"CoinsLabel\\")\\n\\t\\tif coinsLabel and coinsLabel:IsA(\\"TextLabel\\") then\\n\\t\\t\\tcoinsLabel.Text = tostring(count)\\n\\t\\tend\\n\\tend\\nend)\\n\\n-- Update state from gameplay\\ncoins:Set(42)\\n```","source":{"line":111,"path":"src/Flux/init.luau"}}')}}]);